/**
 * Tạo kịch bản TikTok với NGUYÊN TẮC CỘNG ĐỒNG nghiêm ngặt.
 */
export const generateKocScript = async (
  imageParts: any[], productName: string, keyword: string, scriptTone: string,
  productSize: string, scriptNote: string, scriptLayout: string, gender: string, voice: string,
  sceneCount: number
): Promise<ScriptParts> => {
  const ai = getAiClient();

  let dialectInstruction = voice === 'Miền Bắc' 
    ? `VĂN PHONG MIỀN BẮC (HÀ NỘI): dùng nhé, ạ, thế, đấy, chứ.` 
    : `VĂN PHONG MIỀN NAM (SÀI GÒN): dùng nha, nè, nghen, thiệt, hông, vầy.`;

  const prompt = `
    Trong vai 1 Creator chuyên tạo video viral hãy tạo kịch bản bán hàng cho "${productName}". USP: "${keyword}". Layout: "${scriptLayout}". Giới tính: ${gender}.
    YÊU CẦU: Đúng ${sceneCount} phần (v1..v${sceneCount}). KHÔNG nhắc bối cảnh/địa điểm.

    !!! QUAN TRỌNG NHẤT (STRICT LENGTH RULE) !!!:
    Mỗi phần kịch bản (v1, v2...) BẮT BUỘC PHẢI CÓ ĐỘ DÀI TỪ 160 ĐẾN 190 KÝ TỰ. 
    ${dialectInstruction}
    Kịch bản phải bắt đầu bằng một câu hỏi nhức nhối.

    !!! CẢNH BÁO VI PHẠM CỘNG ĐỒNG - TUYỆT ĐỐI KHÔNG SỬ DỤNG CÁC TỪ SAU !!!:
    ${FORBIDDEN_TERMS}
  `;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
    const key = `v${i}`;
    properties[key] = { type: Type.STRING };
    required.push(key);
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.OBJECT, properties, required }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (e) {
    const fallback: ScriptParts = {};
    for (let i = 1; i <= sceneCount; i++) fallback[`v${i}`] = '';
    return fallback;
  }
};

/**
 * Tạo lại một phần kịch bản cụ thể
 */
export const regenerateKocScriptPart = async (
  imageParts: any[], 
  productName: string, 
  keyword: string, 
  scriptPartKey: string,
  currentPartContent: string,
  fullScript: ScriptParts,
  gender: string, 
  voice: string,
  layout: string
): Promise<string> => {
  const ai = getAiClient();
  let dialectInstruction = voice === 'Miền Bắc' 
    ? `VĂN PHONG MIỀN BẮC (HÀ NỘI): dùng nhé, ạ, thế, đấy, chứ.` 
    : `VĂN PHONG MIỀN NAM (SÀI GÒN): dùng nha, nè, nghen, thiệt, hông, vầy.`;

  const prompt = `
    Hãy VIẾT LẠI phần kịch bản "${scriptPartKey}" cho sản phẩm "${productName}".
    Nội dung cũ: "${currentPartContent}".
    Bối cảnh toàn bộ kịch bản: ${JSON.stringify(fullScript)}.
    YÊU CẦU: Độ dài bắt buộc từ 160 đến 190 ký tự. ${dialectInstruction}
    Trả về duy nhất chuỗi ký tự kịch bản mới.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] }
    });
    return response.text?.trim() || currentPartContent;
  } catch (error) {
    return currentPartContent;
  }
};

/**
 * Tạo hình ảnh với ĐỒNG NHẤT TỶ LỆ SẢN PHẨM SO VỚI NHÂN VẬT.
 */
export const generateKocImage = async (
  referenceImageParts: any[], 
  faceImagePart: any | null, 
  outfitImagePart: any | null,
  outfitDescription: string, 
  productName: string,
  scriptPart: string, 
  characterDescription: string, 
  userCustomPrompt: string | undefined, 
  gender: string, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = "",
  visualNote: string = "",
  poseLabel: string = "",
  backgroundReferencePart: any | null = null
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const lifestyleStyle = "Natural lifestyle shot, daily usage scenario, candid photography, realistic natural lighting.";
  const baseStyle = is3D 
    ? `High-quality 3D Animation Pixar style, ${lifestyleStyle}, vibrant colors.`
    : `Photorealistic RAW PHOTO, ${lifestyleStyle}, 8k resolution, authentic skin textures.`;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "no product", "remove product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  const scaleConsistencyRule = `
    !!! CRITICAL SCALE RULE (MANDATORY): PRODUCT-TO-CHARACTER RATIO !!!
    - The product "${productName}" MUST HAVE A FIXED PHYSICAL SIZE relative to the human model.
    - If the product is shown in the reference image as being handheld (size of a palm), it MUST remain exactly that size in the generated image.
    - DO NOT enlarge or shrink the product based on camera distance. The proportion of [Product Size] vs [Character Body Size] must be 100% CONSISTENT with the reference photo.
    - The product must NOT look like a giant version or a miniature version of itself.
  `;

  const visualRules = `
    CRITICAL VISUAL RULES:
    1. ABSOLUTELY NO TEXT, NO LETTERS.
    2. The background must be CLEAN.
    3. NO UI elements, NO watermarks.

    CRITICAL RESTRICTIONS: 
    1. NO CHILDREN. The subject must be an adult Vietnamese ${gender}.
    2. ${is3D ? "High-quality 3D CGI." : "Real photo."}
    ${isNoProductRequested ? '3. ABSOLUTELY NO PRODUCT IN THIS IMAGE.' : `
    3. STRICT PRODUCT FIDELITY:
       - The product "${productName}" MUST MATCH the input reference images 1:1.
       - PRESERVE PATTERNS & TEXTURES.
       ${scaleConsistencyRule}`}
  `;

  const identityRule = faceImagePart 
    ? `IDENTITY: Use facial features from FACE_REFERENCE.`
    : `IDENTITY: Adult Vietnamese ${gender}.`;

  const outfitRule = outfitImagePart ? `OUTFIT: Style from OUTFIT_REFERENCE: "${outfitDescription}".` : "";

  const backgroundRule = backgroundReferencePart 
    ? `ENVIRONMENT: Use background layout from BACKGROUND_REFERENCE.`
    : `ENVIRONMENT: Natural ${backgroundNote || 'daily lifestyle setting'}.`;

  const sceneInstruction = `SCENE: Context: "${scriptPart}". ${poseLabel ? `Pose: ${poseLabel}.` : ""}`;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    CHARACTER: ${characterDescription}. Vietnamese ${gender}.
    ${identityRule}
    ${outfitRule}
    ${backgroundRule}
    ${visualRules}
    ${visualNote ? `VISUAL COMPOSITION: ${visualNote}.` : ""}
    ${sceneInstruction} 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (backgroundReferencePart) contents.push({ inlineData: backgroundReferencePart });
  if (!isNoProductRequested) referenceImageParts.forEach(part => contents.push({ inlineData: part }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

/**
 * Generates a video prompt for VEO-3 model.
 */
export const generateKocVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceTag = voice === 'Miền Bắc' ? 'Northern Vietnamese' : 'Southern Vietnamese';
  const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

  const scaleRule = `- CRITICAL: The product "${productName}" must maintain a consistent size ratio relative to the character. It should not change scale during movement.`;

  const productInteractionRule = isNoProductRequested
    ? `PHẦN 2: HÀNH ĐỘNG:
      - TUYỆT ĐỐI KHÔNG xuất hiện sản phẩm "${productName}".
      - Nhân vật tương tác phù hợp kịch bản: "${scriptText}".`
    : `PHẦN 2: HÀNH ĐỘNG:
      - Nhân vật cầm sản phẩm "${productName}".
      - ${scaleRule}
      - Sản phẩm phải giống ảnh tham chiếu 100%, không biến dạng.`;

  const instructionPrompt = `
  Nhiệm vụ: Viết video prompt chi tiết cho VEO-3 dài 8 giây.
  PHONG CÁCH: ${is3D ? "3D Animation" : "Photorealistic"}.

  CẤU TRÚC PROMPT:
  PHẦN 1: NHÂN VẬT: Người Việt Nam. ${is3D ? "Pixar style." : "Real life."}
  ${productInteractionRule}
  PHẦN 3: BỐI CẢNH & ÁNH SÁNG.
  PHẦN 4: CHUYỂN ĐỘNG MÁY ẢNH (9:16).
  PHẦN 5: LỜI THOẠI: ✨ Model speaks in ${voiceTag} voice (${voiceGender}): "${scriptText}"
  PHẦN 6: KỸ THUẬT: 4K, 60fps.

  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất (trừ lời thoại).`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  if (generatedImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: contents }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) { return "Error generating video prompt."; }
};

import React from 'react';

interface ScriptSectionProps {
  title: string;
  content: string;
  color: string;
  onChange: (newText: string) => void;
  onRegenerate?: () => void;
  isRegenerating?: boolean;
}

const ScriptSection: React.FC<ScriptSectionProps> = ({ 
  title, 
  content, 
  color, 
  onChange, 
  onRegenerate,
  isRegenerating 
}) => {
  const charCount = content ? content.length : 0;

  // Logic kiểm tra độ dài theo yêu cầu (160 - 190)
  const isValid = charCount >= 160 && charCount <= 190;
  const isTooShort = charCount > 0 && charCount < 160;
  const isTooLong = charCount > 190;

  return (
    <div className={`p-4 rounded-xl border-l-4 ${color} bg-white shadow-sm mb-4 group transition-all ${isValid ? 'ring-1 ring-green-100 bg-green-50/10' : ''}`}>
      <div className="flex justify-between items-center mb-2">
        <h3 className="text-xs font-bold uppercase tracking-wider text-slate-500">{title}</h3>
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
           <svg className="w-3 h-3 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
           <span className="text-[10px] text-slate-400">Click to edit</span>
        </div>
      </div>

      <div className="relative">
        <textarea
          className={`w-full text-slate-800 text-sm leading-relaxed font-semibold resize-y min-h-[180px] focus:outline-none focus:bg-slate-50 rounded p-2 -ml-2 bg-transparent border border-transparent hover:border-slate-200 transition-all ${isRegenerating ? 'opacity-30 pointer-events-none' : ''}`}
          value={content || ""}
          onChange={(e) => onChange(e.target.value)}
          placeholder="Đang chờ kịch bản..."
        />
        {isRegenerating && (
          <div className="absolute inset-0 flex items-center justify-center bg-white/50">
            <div className="w-6 h-6 border-2 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
        )}
      </div>

      <div className="mt-2 flex justify-between items-center border-t border-slate-50 pt-2">
        {onRegenerate ? (
          <button 
            onClick={onRegenerate}
            disabled={isRegenerating}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all shadow-sm ${
              isValid 
              ? 'bg-slate-100 text-slate-500 hover:bg-orange-600 hover:text-white' 
              : 'bg-orange-600 text-white hover:bg-orange-700 animate-pulse'
            } disabled:opacity-50`}
          >
            <svg className={`w-3 h-3 ${isRegenerating ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
            Tạo lại
          </button>
        ) : (
          <div className="text-[9px] font-bold text-slate-300 uppercase tracking-tighter italic">
            {isValid ? 'Đạt mục tiêu ✓' : 'Cần 160-190 ký tự'}
          </div>
        )}

        <span className={`text-[10px] px-2 py-1 rounded-full font-black tabular-nums transition-all ${
            isValid 
            ? 'bg-green-100 text-green-700' 
            : isTooLong || isTooShort 
                ? 'bg-red-100 text-red-600 animate-pulse' 
                : 'bg-slate-100 text-slate-500'
        }`}>
          {charCount} / 190
        </span>
      </div>
    </div>
  );
};

export default ScriptSection;

