const KocReviewModule: React.FC = () => {
  const storageKey = "koc_project_v15_full_media";
  const [state, setState] = useState<any>({
    faceFile: null,
    facePreviewUrl: null,
    outfitFile: null,
    outfitPreviewUrl: null,
    outfitDescription: '',
    isExtractingOutfit: false,
    backgroundFile: null,
    backgroundPreviewUrl: null,
    characterDescription: '',
    gender: 'Nữ',
    voice: 'Miền Bắc',
    imageStyle: 'Realistic',
    sceneCount: 5,
    productFiles: [], 
    productPreviewUrls: [],
    productName: '',
    keyword: '',
    scriptTone: '',
    productSize: '',
    scriptNote: '', 
    visualNote: '',
    scriptLayout: '',
    isGeneratingScript: false,
    isRegeneratingPart: {},
    script: null,
    images: {},
    videoPrompts: {}
  });

  const productInputRef = useRef<HTMLInputElement>(null);
  const faceInputRef = useRef<HTMLInputElement>(null);
  const outfitInputRef = useRef<HTMLInputElement>(null);
  const backgroundInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed && typeof parsed === 'object') {
          setState((prev: any) => ({
            ...prev,
            ...parsed,
            // Reset files because they can't be stored in localStorage as objects, 
            // but we keep PreviewUrls if they are base64 from an import
            productFiles: [],
            faceFile: null,
            outfitFile: null,
            backgroundFile: null,
            isGeneratingScript: false,
            isExtractingOutfit: false,
            isRegeneratingPart: {}
          }));
        }
      }
    } catch (e) {
      console.error("Failed to restore KOC state", e);
    }
  }, []);

  useEffect(() => {
    try {
      const { isGeneratingScript, isExtractingOutfit, isRegeneratingPart, productFiles, faceFile, outfitFile, backgroundFile, images, ...persistentData } = state;
      // We don't save large base64 strings to LocalStorage to avoid QuotaExceededError
      // LocalStorage only keeps text data and small states
      const safeImages = Object.keys(images || {}).reduce((acc: any, key) => {
        acc[key] = { ...images[key], url: '' };
        return acc;
      }, {});
      localStorage.setItem(storageKey, JSON.stringify({ ...persistentData, images: safeImages }));
    } catch (e) {
      console.error("Failed to save KOC state", e);
    }
  }, [state]);

  // Handle Global Import / Export
  useEffect(() => {
    const handleExport = async () => {
      const getBase64 = async (file: File | null, fallbackUrl: string | null) => {
        if (file) {
          const part = await service.fileToGenerativePart(file);
          return `data:${part.mimeType};base64,${part.data}`;
        }
        if (fallbackUrl?.startsWith('data:')) return fallbackUrl;
        return "";
      };

      // Convert all input media to base64
      const productImagesBase64 = await Promise.all(
        state.productFiles.length > 0 
          ? state.productFiles.map((f: File) => getBase64(f, null))
          : state.productPreviewUrls.map((url: string) => url.startsWith('data:') ? Promise.resolve(url) : Promise.resolve(""))
      );

      const faceBase64 = await getBase64(state.faceFile, state.facePreviewUrl);
      const outfitBase64 = await getBase64(state.outfitFile, state.outfitPreviewUrl);
      const backgroundBase64 = await getBase64(state.backgroundFile, state.backgroundPreviewUrl);

      const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
      const exportData = activeKeys.map((key, index) => ({
        stt: index + 1,
        inputs: {
          productName: state.productName,
          keyword: state.keyword,
          characterDescription: state.characterDescription,
          outfitDescription: state.outfitDescription,
          visualNote: state.visualNote,
          scriptNote: state.scriptNote, 
          // Package all input media into the first record or every record for safety
          inputMedia: {
            productImages: productImagesBase64.filter(i => i),
            faceImage: faceBase64,
            outfitImage: outfitBase64,
            backgroundImage: backgroundBase64
          },
          settings: {
            gender: state.gender,
            voice: state.voice,
            imageStyle: state.imageStyle,
            scriptLayout: state.scriptLayout,
            pose: state.images[key]?.pose || ''
          }
        },
        script: state.script ? state.script[key] : '',
        outputImage: state.images[key]?.url || '',
        videoPrompt: state.videoPrompts[key]?.text || ''
      }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: exportData, moduleName: 'KOC_Project_Complete' } 
      }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      if (!obj) return undefined;
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData) || importedData.length === 0) return;

      const firstItem = importedData[0];
      const inputs = smartFind(firstItem, ['inputs', 'input', 'data']) || {};
      const settings = smartFind(inputs, ['settings', 'config']) || {};
      const media = smartFind(inputs, ['inputMedia', 'media']) || {};

      const newState = {
        ...state,
        productName: smartFind(inputs, ['productName', 'name']) || state.productName,
        keyword: smartFind(inputs, ['keyword', 'usp']) || state.keyword,
        characterDescription: smartFind(inputs, ['characterDescription', 'character']) || state.characterDescription,
        outfitDescription: smartFind(inputs, ['outfitDescription', 'outfit']) || state.outfitDescription,
        visualNote: smartFind(inputs, ['visualNote']) || state.visualNote,
        scriptNote: smartFind(inputs, ['scriptNote', 'note']) || state.scriptNote,
        gender: smartFind(settings, ['gender']) || state.gender,
        voice: smartFind(settings, ['voice']) || state.voice,
        imageStyle: smartFind(settings, ['imageStyle']) || state.imageStyle,
        scriptLayout: smartFind(settings, ['scriptLayout', 'layout']) || state.scriptLayout,
        sceneCount: importedData.length,
        // Restore media previews from base64
        productPreviewUrls: smartFind(media, ['productImages', 'images']) || [],
        facePreviewUrl: smartFind(media, ['faceImage', 'face']) || "",
        outfitPreviewUrl: smartFind(media, ['outfitImage', 'outfit_img']) || "",
        backgroundPreviewUrl: smartFind(media, ['backgroundImage', 'background']) || "",
        script: {},
        images: {},
        videoPrompts: {}
      };

      const total = importedData.length;
      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        const itemInputs = smartFind(item, ['inputs', 'input']) || {};
        const itemSettings = smartFind(itemInputs, ['settings']) || {};
        const key = `v${i + 1}`;

        newState.script[key] = smartFind(item, ['script', 'content', 'text']) || '';
        newState.images[key] = {
          url: smartFind(item, ['outputImage', 'image', 'base64']) || '',
          loading: false,
          pose: smartFind(itemSettings, ['pose']) || '',
          customPrompt: ''
        };
        newState.videoPrompts[key] = {
          text: smartFind(item, ['videoPrompt', 'prompt']) || '',
          loading: false,
          visible: !!smartFind(item, ['videoPrompt', 'prompt'])
        };

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { 
          detail: { percent, complete: i === total - 1 } 
        }));
        await new Promise(r => setTimeout(r, 50));
      }

      setState(newState);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [state]);

  const handleProductFilesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const selectedFiles = Array.from(e.target.files);
      const updatedFiles = [...state.productFiles, ...selectedFiles].slice(0, 3);
      const updatedUrls = updatedFiles.map(f => URL.createObjectURL(f));
      setState((prev: any) => ({
        ...prev,
        productFiles: updatedFiles,
        productPreviewUrls: updatedUrls
      }));
    }
    if (productInputRef.current) productInputRef.current.value = "";
  };

  const removeProductFile = (idx: number) => {
    const updatedFiles = state.productFiles.filter((_: any, i: number) => i !== idx);
    const updatedUrls = updatedFiles.map((f: File) => URL.createObjectURL(f));
    // If no files left but we have imported previews, clear them too
    const updatedPreviewUrls = state.productPreviewUrls.filter((_: any, i: number) => i !== idx);
    setState((prev: any) => ({
      ...prev,
      productFiles: updatedFiles,
      productPreviewUrls: updatedFiles.length > 0 ? updatedUrls : updatedPreviewUrls
    }));
  };

  const handleFaceFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({
        ...prev,
        faceFile: file,
        facePreviewUrl: URL.createObjectURL(file)
      }));
    }
  };

  const handleOutfitFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({
        ...prev,
        outfitFile: file,
        outfitPreviewUrl: URL.createObjectURL(file),
        outfitDescription: ''
      }));
    }
  };

  const handleBackgroundFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({
        ...prev,
        backgroundFile: file,
        backgroundPreviewUrl: URL.createObjectURL(file)
      }));
    }
  };

  const handleExtractOutfit = async () => {
    let part = null;
    if (state.outfitFile) {
        part = await service.fileToGenerativePart(state.outfitFile);
    } else if (state.outfitPreviewUrl?.startsWith('data:')) {
        part = { mimeType: 'image/png', data: state.outfitPreviewUrl.split(',')[1] };
    }

    if (!part) return;
    setState(p => ({ ...p, isExtractingOutfit: true }));
    try {
      const desc = await service.describeKocOutfit(part);
      setState(p => ({ ...p, outfitDescription: desc, isExtractingOutfit: false }));
    } catch (e) {
      console.error(e);
      setState(p => ({ ...p, isExtractingOutfit: false }));
    }
  };

  const handleGenerate = async () => {
    if (state.productFiles.length === 0 && state.productPreviewUrls.length === 0) {
      alert("Vui lòng tải ảnh sản phẩm.");
      return;
    }
    if (!state.productName) {
      alert("Vui lòng nhập tên sản phẩm.");
      return;
    }

    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    const initialImages: any = {};
    const initialPrompts: any = {};
    activeKeys.forEach(k => {
      initialImages[k] = { url: '', loading: false, customPrompt: '', pose: '' };
      initialPrompts[k] = { text: '', loading: false, visible: false };
    });

    setState((prev: any) => ({
      ...prev,
      isGeneratingScript: true,
      script: null,
      images: initialImages,
      videoPrompts: initialPrompts
    }));

    try {
      let imageParts = [];
      if (state.productFiles.length > 0) {
        imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        imageParts = state.productPreviewUrls.map((url: string) => ({
          mimeType: 'image/png',
          data: url.split(',')[1]
        }));
      }

      let layoutToUse = state.scriptLayout;
      if (!layoutToUse) layoutToUse = LAYOUT_OPTIONS[Math.floor(Math.random() * LAYOUT_OPTIONS.length)];

      const script = await service.generateKocScript(
        imageParts,
        state.productName,
        state.keyword,
        state.scriptTone,
        state.productSize,
        state.scriptNote,
        layoutToUse,
        state.gender,
        state.voice,
        state.sceneCount
      );
      setState((prev: any) => ({ ...prev, script, scriptLayout: layoutToUse }));
    } catch (e) {
      console.error(e);
    } finally {
      setState((prev: any) => ({ ...prev, isGeneratingScript: false }));
    }
  };

  const handleRegenerateScriptPart = async (key: string) => {
    if (state.isGeneratingScript || state.isRegeneratingPart[key] || !state.script) return;

    setState((p: any) => ({ 
      ...p, 
      isRegeneratingPart: { ...p.isRegeneratingPart, [key]: true } 
    }));

    try {
      let imageParts = [];
      if (state.productFiles.length > 0) {
        imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        imageParts = state.productPreviewUrls.map((url: string) => ({
          mimeType: 'image/png',
          data: url.split(',')[1]
        }));
      }

      const newPartContent = await service.regenerateKocScriptPart(
        imageParts,
        state.productName,
        state.keyword,
        key,
        state.script[key],
        state.script,
        state.gender,
        state.voice,
        state.scriptLayout
      );

      setState((p: any) => ({
        ...p,
        script: { ...p.script, [key]: newPartContent },
        isRegeneratingPart: { ...p.isRegeneratingPart, [key]: false }
      }));
    } catch (error) {
      console.error("Regen script part failed", error);
      setState((p: any) => ({ 
        ...p, 
        isRegeneratingPart: { ...p.isRegeneratingPart, [key]: false } 
      }));
    }
  };

  const handleGenImageForKey = async (key: string) => {
    setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: true } } }));
    try {
      let productParts = [];
      if (state.productFiles.length > 0) {
        productParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        productParts = state.productPreviewUrls.map((url: string) => ({
          mimeType: 'image/png',
          data: url.split(',')[1]
        }));
      }

      const getPart = async (file: File | null, url: string | null) => {
        if (file) return await service.fileToGenerativePart(file);
        if (url?.startsWith('data:')) return { mimeType: 'image/png', data: url.split(',')[1] };
        return null;
      };

      const facePart = await getPart(state.faceFile, state.facePreviewUrl);
      const outfitPart = await getPart(state.outfitFile, state.outfitPreviewUrl);
      const bgRefPart = await getPart(state.backgroundFile, state.backgroundPreviewUrl);

      const currentPoseKey = state.images[key]?.pose || "";
      const poseLabel = KOC_POSES.find(p => p.value === currentPoseKey)?.label || "";

      const url = await service.generateKocImage(
        productParts,
        facePart,
        outfitPart,
        state.outfitDescription,
        state.productName,
        state.script[key],
        state.characterDescription,
        state.images[key]?.customPrompt,
        state.gender,
        state.imageStyle,
        state.scriptNote,
        state.visualNote,
        poseLabel,
        bgRefPart
      );
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], url, loading: false } } }));
    } catch (e) {
      console.error(e);
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: false, error: 'Failed' } } }));
    }
  };

  const handleBulkImage = async () => {
    const keys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    for (const key of keys) {
      await handleGenImageForKey(key);
    }
  };

  const handleGeneratePromptForKey = async (key: string) => {
    setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: true, visible: true } } }));
    try {
      let productImageData = "";
      if (state.productFiles.length > 0) {
        const p = await service.fileToGenerativePart(state.productFiles[0]);
        productImageData = p.data;
      } else if (state.productPreviewUrls.length > 0) {
        productImageData = state.productPreviewUrls[0].split(',')[1];
      }

      const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
      const customPrompt = state.images[key]?.customPrompt || "";
      const isNoProduct = noProductKeywords.some(kw => customPrompt.toLowerCase().includes(kw));

      const prompt = await service.generateKocVeoPrompt(
        state.productName,
        state.script[key],
        state.gender,
        state.voice,
        productImageData,
        state.images[key].url,
        isNoProduct,
        state.imageStyle
      );
      setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { text: prompt, loading: false, visible: true } } }));
    } catch (e) {
      setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: false } } }));
    }
  };

  const handleBulkPrompt = async () => {
    const keys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    for (const key of keys) {
      await handleGeneratePromptForKey(key);
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') {
      alert("Đang tải thư viện nén, vui lòng thử lại sau giây lát.");
      return;
    }

    const zip = new JSZip();
    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    let count = 0;

    for (let i = 0; i < activeKeys.length; i++) {
      const key = activeKeys[i];
      const imageData = state.images[key];
      if (imageData?.url) {
        const base64Data = imageData.url.split(',')[1];
        if (base64Data) {
          const fileName = `${String(i + 1).padStart(2, '0')}.png`;
          zip.file(fileName, base64Data, { base64: true });
          count++;
        }
      }
    }

    if (count === 0) {
      alert("Không có ảnh nào để tải xuống.");
      return;
    }

    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `koc_images_${state.productName || 'project'}.zip`;
    link.click();
  };

  const downloadAllPrompts = () => {
    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    const text = activeKeys
      .map(key => state.videoPrompts[key]?.text || "")
      .filter(t => t.trim().length > 0)
      .map(t => t.replace(/\n/g, ' '))
      .join('\n');

    if (!text) {
      alert("Vui lòng tạo Video Prompt trước khi tải xuống.");
      return;
    }

    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `prompts_${state.productName || 'koc'}.txt`;
    link.click();
  };

  const hasGeneratedItems = state.script && Object.values(state.images).some((img: any) => img.url);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 mb-8">
        <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
          <div className="md:col-span-5 flex flex-col gap-4">
            <div className="space-y-3">
              <label className="block text-sm font-bold text-slate-700">1. Hình ảnh sản phẩm (Chọn tối đa 3 ảnh)</label>
              <div 
                onClick={() => productInputRef.current?.click()} 
                className="w-full h-32 rounded-xl border-2 border-dashed border-slate-300 flex flex-col items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 transition-all border-[#ff5722]/20 group"
              >
                <div className="flex flex-col items-center opacity-40 group-hover:opacity-60 transition-opacity">
                  <svg className="w-8 h-8 text-[#ff5722] mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                  <span className="text-[10px] font-black uppercase tracking-widest">Tải ảnh sản phẩm (Multiple)</span>
                </div>
                <input type="file" multiple ref={productInputRef} onChange={handleProductFilesChange} className="hidden" accept="image/*" />
              </div>

              {state.productPreviewUrls.length > 0 && (
                <div className="grid grid-cols-3 gap-3 pt-1">
                  {state.productPreviewUrls.map((url: string, idx: number) => (
                    <div key={idx} className="relative aspect-[3/4] rounded-lg overflow-hidden border border-slate-200 group/item shadow-sm">
                      <img src={url} className="w-full h-full object-cover" />
                      <button 
                        onClick={() => removeProductFile(idx)}
                        className="absolute top-1 right-1 bg-black/50 hover:bg-red-600 text-white p-1 rounded-full opacity-0 group-item/item:opacity-100 transition-opacity"
                      >
                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="space-y-1">
              <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Ghi chú nhân vật</label>
              <textarea
                value={state.characterDescription}
                onChange={e => setState(p => ({ ...p, characterDescription: e.target.value }))}
                placeholder="Mô tả phong cách, diện mạo nhân vật..."
                className="w-full p-3 border rounded-xl h-24 text-sm focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="block text-sm font-bold text-slate-700">0. Ảnh mặt mẫu</label>
                <div onClick={() => faceInputRef.current?.click()} className="relative w-full aspect-square rounded-xl border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors overflow-hidden">
                  {state.facePreviewUrl ? <img src={state.facePreviewUrl} className="h-full object-cover" /> : <span className="text-slate-400 text-[10px] uppercase font-bold text-center p-2">Mặt mẫu</span>}
                  <input type="file" ref={faceInputRef} onChange={handleFaceFileChange} className="hidden" accept="image/*" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="block text-sm font-bold text-slate-700">2. Ảnh trang phục</label>
                <div onClick={() => outfitInputRef.current?.click()} className="relative w-full aspect-square rounded-xl border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors overflow-hidden">
                  {state.outfitPreviewUrl ? <img src={state.outfitPreviewUrl} className="h-full object-cover" /> : <span className="text-slate-400 text-[10px] uppercase font-bold text-center p-2">Trang phục</span>}
                  <input type="file" ref={outfitInputRef} onChange={handleOutfitFileChange} className="hidden" accept="image/*" />
                </div>
                {(state.outfitFile || state.outfitPreviewUrl?.startsWith('data:')) && (
                  <button
                    onClick={handleExtractOutfit}
                    disabled={state.isExtractingOutfit}
                    className={`w-full py-2 rounded-lg text-[10px] font-black uppercase transition-all shadow-sm ${state.outfitDescription ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-blue-600 text-white hover:bg-blue-700'}`}
                  >
                    {state.isExtractingOutfit ? "Đang tách..." : state.outfitDescription ? "Đã tách xong ✓" : "Tách trang phục"}
                  </button>
                )}
              </div>
            </div>

            {state.outfitDescription && (
              <div className="p-3 bg-slate-50 border rounded-xl animate-fadeIn">
                <label className="block text-[8px] font-black text-slate-400 uppercase mb-1">Kết quả tách trang phục (AI focus):</label>
                <p className="text-[10px] text-slate-600 italic leading-relaxed line-clamp-3">"{state.outfitDescription}"</p>
              </div>
            )}
          </div>

          <div className="md:col-span-7 space-y-4">
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Tên sản phẩm</label>
                <input type="text" value={state.productName} onChange={e => setState(p => ({ ...p, productName: e.target.value }))} placeholder="Nhập tên sản phẩm..." className="w-full p-3 border rounded-xl focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all" />
              </div>
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">USP sản phẩm (Đặc điểm nổi bật, công dụng, giá trị...)</label>
                <textarea
                  value={state.keyword}
                  onChange={e => setState(p => ({ ...p, keyword: e.target.value }))}
                  placeholder="Điền các điểm USP nổi bật của sản phẩm..."
                  className="w-full p-3 border rounded-xl h-24 text-sm focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all"
                />
              </div>
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Ghi chú hiển thị (Visual Appearance)</label>
                <textarea
                  value={state.visualNote}
                  onChange={e => setState(p => ({ ...p, visualNote: e.target.value }))}
                  placeholder="Mô tả cách sản phẩm và nhân vật xuất hiện (VD: nhân vật đứng cạnh sản phẩm...)"
                  className="w-full p-3 border rounded-xl h-20 text-sm focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Giới tính nhân vật</label>
                <select value={state.gender} onChange={e => setState(p => ({ ...p, gender: e.target.value }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none">
                  <option value="Nữ">Nữ</option>
                  <option value="Nam">Nam</option>
                </select>
              </div>
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Giọng điệu</label>
                <select value={state.voice} onChange={e => setState(p => ({ ...p, voice: e.target.value }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none">
                  <option value="Miền Bắc">Miền Bắc</option>
                  <option value="Miền Nam">Miền Nam</option>
                </select>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Thời lượng (Scenes)</label>
                <select value={state.sceneCount} onChange={e => setState(p => ({ ...p, sceneCount: parseInt(e.target.value) }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none font-bold text-orange-600">
                  {SCENE_COUNT_OPTIONS.map(opt => (
                    <option key={opt.count} value={opt.count}>{opt.label}</option>
                  ))}
                </select>
              </div>
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Phong cách ảnh (Lifestyle)</label>
                <div className="flex bg-slate-50 p-1 rounded-xl border border-slate-200">
                  <button
                    onClick={() => setState(p => ({ ...p, imageStyle: 'Realistic' }))}
                    className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${state.imageStyle === 'Realistic' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    Chân thực
                  </button>
                  <button
                    onClick={() => setState(p => ({ ...p, imageStyle: '3D' }))}
                    className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${state.imageStyle === '3D' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    3D Animation
                  </button>
                </div>
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Bố cục kịch bản (Layout)</label>
              <select value={state.scriptLayout} onChange={e => setState(p => ({ ...p, scriptLayout: e.target.value }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none">
                <option value="">-- Random Layout --</option>
                {LAYOUT_OPTIONS.map(o => <option key={o} value={o}>{o}</option>)}
              </select>
            </div>

            <div className="space-y-1">
              <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Background bối cảnh (Bắt buộc dùng cho ảnh)</label>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div 
                  onClick={() => backgroundInputRef.current?.click()}
                  className="aspect-video border-2 border-dashed border-slate-300 rounded-xl flex items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors overflow-hidden group"
                >
                  {state.backgroundPreviewUrl ? (
                    <img src={state.backgroundPreviewUrl} className="h-full w-full object-cover" />
                  ) : (
                    <div className="text-center p-4">
                      <svg className="w-8 h-8 text-slate-300 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                      <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Tải ảnh bối cảnh</span>
                    </div>
                  )}
                  <input type="file" ref={backgroundInputRef} onChange={handleBackgroundFileChange} className="hidden" accept="image/*" />
                </div>
                <textarea
                  value={state.scriptNote}
                  onChange={e => setState(p => ({ ...p, scriptNote: e.target.value }))}
                  placeholder="Mô tả bối cảnh chi tiết bằng chữ (VD: phòng khách sang trọng, ánh sáng ấm...)"
                  className="w-full p-3 border rounded-xl h-full text-sm focus:ring-2 focus:ring-orange-100 focus:border-orange-400 outline-none transition-all resize-none font-medium"
                />
              </div>
            </div>

            <button onClick={handleGenerate} disabled={state.isGeneratingScript} className="w-full py-4 bg-orange-600 text-white font-black rounded-xl shadow-lg disabled:opacity-50 hover:bg-orange-700 transition-all active:scale-[0.98] uppercase tracking-widest">
              {state.isGeneratingScript ? "Đang xử lý kịch bản..." : "Bắt đầu tạo kịch bản"}
            </button>
          </div>
        </div>
      </div>

      {state.script && (
        <div className="space-y-8 pb-32">
          <div className="bg-slate-900 p-6 rounded-2xl border border-slate-800 shadow-sm">
            <h3 className="text-sm font-black text-white uppercase tracking-tight">KẾT QUẢ CHIẾN DỊCH (LIFESTYLE MODE)</h3>
            <p className="text-[10px] font-bold text-orange-500 uppercase tracking-widest">
              Đã tạo xong {state.sceneCount} cảnh ({state.sceneCount * 8}s) • Style: {state.imageStyle === 'Realistic' ? 'Chân thực' : '3D Animation'}
            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6">
            {Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`).map((key, idx) => (
              <div key={key} className="space-y-4">
                <ScriptSection
                  title={`Phần ${idx + 1}`}
                  content={state.script[key]}
                  color="border-orange-500"
                  onChange={(val) => setState(p => ({ ...p, script: { ...p.script, [key]: val } }))}
                  onRegenerate={() => handleRegenerateScriptPart(key)}
                  isRegenerating={state.isRegeneratingPart[key]}
                />
                <ImageCard
                  label={`Cảnh ${idx + 1}`}
                  imageData={state.images[key]}
                  videoPrompt={state.videoPrompts[key]}
                  onGeneratePrompt={() => handleGeneratePromptForKey(key)}
                  onRegenerate={() => handleGenImageForKey(key)}
                  onTranslate={() => { }}
                  pose={state.images[key]?.pose || ''}
                  onPoseChange={(val) => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], pose: val } } }))}
                  customPrompt={state.images[key]?.customPrompt || ''}
                  onCustomPromptChange={(val) => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], customPrompt: val } } }))}
                />
              </div>
            ))}
          </div>

          <div className="flex flex-col items-center gap-12 py-12">
            <div className="flex flex-col md:flex-row gap-4 w-full justify-center px-4">
              <button
                onClick={handleBulkImage}
                className="w-full md:w-auto px-12 py-5 bg-orange-600 text-white font-black rounded-2xl shadow-2xl hover:scale-105 active:scale-95 transition-all text-lg flex items-center justify-center gap-4 uppercase tracking-widest"
              >
                TỰ ĐỘNG TẠO TẤT CẢ ẢNH
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H4zm12 12H4l4-8 3 6 2-4 3 6z" clipRule="evenodd" /></svg>
              </button>
              <button
                onClick={handleBulkPrompt}
                className="w-full md:w-auto px-12 py-5 bg-slate-900 text-white font-black rounded-2xl shadow-2xl hover:scale-105 active:scale-95 transition-all text-lg flex items-center justify-center gap-4 uppercase tracking-widest"
              >
                TỰ ĐỘNG VIẾT TẤT CẢ PROMPTS
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14H11V21L20 10H13Z" /></svg>
              </button>
            </div>

            {hasGeneratedItems && (
              <div className="flex flex-col md:flex-row items-center justify-center gap-4 border-t border-slate-200 w-full pt-12">
                <button
                  onClick={downloadAllImages}
                  className="w-full md:w-auto px-12 py-5 bg-slate-900 text-white font-black rounded-2xl shadow-xl hover:bg-black transition-all active:scale-[0.98] flex items-center justify-center gap-3 uppercase tracking-widest text-base"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  Tải toàn bộ ảnh (ZIP)
                </button>
                <button
                  onClick={downloadAllPrompts}
                  className="w-full md:w-auto px-12 py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl hover:bg-orange-700 transition-all active:scale-[0.98] flex items-center justify-center gap-3 uppercase tracking-widest text-base"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1.01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                  Tải File Prompt (.txt)
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default KocReviewModule;

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/shopee8sService';
import { Shopee8sProduct, ScriptParts, VideoPromptState, GeneratedImage } from '../types';
import ScriptSection from '../components/ScriptSection';
import ImageCard from '../components/ImageCard';

declare var JSZip: any;

const Shopee8sModule: React.FC = () => {
  const storageKey = "shopee8s_project_v10_media_sync";
  const [products, setProducts] = useState<Shopee8sProduct[]>(
    Array.from({ length: 5 }, (_, i) => ({
      id: i + 1,
      name: '',
      usp: '',
      background: '',
      action: '',
      file: null,
      previewUrl: null,
      script: null,
      images: {},
      videoPrompts: {},
      isLoading: false
    }))
  );

  const [faceFile, setFaceFile] = useState<File | null>(null);
  const [facePreview, setFacePreview] = useState<string | null>(null);
  const [gender, setGender] = useState<string>('Nữ');
  const [voice, setVoice] = useState<string>('Miền Bắc (Hà Nội)');
  const [imageStyle, setImageStyle] = useState<'Realistic' | '3D'>('Realistic');
  const [commonNote, setCommonNote] = useState('');
  const [isGlobalLoading, setIsGlobalLoading] = useState(false);

  const fileInputRefs = useRef<(HTMLInputElement | null)[]>([]);
  const faceInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.products) {
          setProducts(prev => prev.map(p => {
            const savedP = parsed.products.find((sp: any) => sp.id === p.id);
            return savedP ? { 
              ...p, 
              ...savedP, 
              file: null, 
              // Note: We don't restore Base64 to LocalStorage to avoid quota limits, 
              // Base64 is only used for JSON Import/Export.
              isLoading: false,
              images: savedP.images || {},
              videoPrompts: savedP.videoPrompts || {}
            } : p;
          }));
        }
        if (parsed.commonNote) setCommonNote(parsed.commonNote);
        if (parsed.gender) setGender(parsed.gender);
        if (parsed.voice) setVoice(parsed.voice);
        if (parsed.imageStyle) setImageStyle(parsed.imageStyle);
      }
    } catch (e) { console.error("Restore fail", e); }
  }, []);

  useEffect(() => {
    try {
      const persistentProducts = products.map(({ file, previewUrl, isLoading, images, videoPrompts, ...rest }) => {
        const safeImages = Object.keys(images || {}).reduce((acc: any, key) => {
           acc[key] = { ...images[key], url: '' }; 
           return acc;
        }, {});
        return { 
          ...rest, 
          images: safeImages, 
          videoPrompts: videoPrompts || {} 
        };
      });
      localStorage.setItem(storageKey, JSON.stringify({ products: persistentProducts, commonNote, gender, voice, imageStyle }));
    } catch (e) { }
  }, [products, commonNote, gender, voice, imageStyle]);

  // Helper to get Base64 from File or existing Base64 URL
  const getMediaBase64 = async (file: File | null, existingUrl: string | null) => {
    if (file) {
      const part = await service.fileToGenerativePart(file);
      return `data:${part.mimeType};base64,${part.data}`;
    }
    if (existingUrl?.startsWith('data:')) return existingUrl;
    return null;
  };

  // Helper to convert File/Base64 to AI Part
  const getPartFromInput = async (file: File | null, url: string | null) => {
    if (file) return await service.fileToGenerativePart(file);
    if (url?.startsWith('data:')) {
      return { mimeType: 'image/png', data: url.split(',')[1] };
    }
    return null;
  };

  // Handle Global Import / Export with Media
  useEffect(() => {
    const handleExport = async () => {
      const faceBase64 = await getMediaBase64(faceFile, facePreview);

      const exportDataPromises = products.map(async (p) => {
        if (!p.script) return null;

        const productBase64 = await getMediaBase64(p.file, p.previewUrl);

        return ['v1', 'v2', 'v3', 'v4'].map(key => ({
          inputs: {
            productName: p.name,
            usp: p.usp,
            background: p.background,
            action: p.action,
            // Package media into JSON
            inputMedia: {
              productImage: productBase64,
              faceImage: faceBase64
            },
            settings: {
              gender,
              voice,
              imageStyle,
              commonNote
            }
          },
          script: (p.script as any)[key],
          outputImage: p.images[key]?.url || '',
          videoPrompt: p.videoPrompts[key]?.text || ''
        }));
      });

      const results = (await Promise.all(exportDataPromises)).filter(r => r !== null).flat();
      const finalExport = results.map((item, idx) => ({ ...item, stt: idx + 1 }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: finalExport, moduleName: 'Shopee_Video_Full_Media' } 
      }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      if (!obj) return undefined;
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData) || importedData.length === 0) return;

      const newProducts = Array.from({ length: 5 }, (_, i) => ({
        id: i + 1,
        name: '',
        usp: '',
        background: '',
        action: '',
        file: null,
        previewUrl: null,
        script: null,
        images: {},
        videoPrompts: {},
        isLoading: false
      }));

      const total = importedData.length;
      let importedFaceBase64 = "";

      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        const inputs = smartFind(item, ['inputs', 'data']) || {};
        const media = smartFind(inputs, ['inputMedia', 'media']) || {};
        const settings = smartFind(inputs, ['settings', 'config']) || {};

        const prodIndex = Math.floor(i / 4);
        if (prodIndex >= newProducts.length) break;

        const prod = newProducts[prodIndex];
        prod.name = smartFind(inputs, ['productName', 'name']) || prod.name;
        prod.usp = smartFind(inputs, ['usp', 'keyword']) || prod.usp;
        prod.background = smartFind(inputs, ['background']) || prod.background;
        prod.action = smartFind(inputs, ['action']) || prod.action;

        // Restore product image from Base64
        const pImg = smartFind(media, ['productImage', 'product_img']);
        if (pImg && !prod.previewUrl) prod.previewUrl = pImg;

        // Restore face image from Base64 (shared)
        const fImg = smartFind(media, ['faceImage', 'face']);
        if (fImg) importedFaceBase64 = fImg;

        if (!prod.script) prod.script = { v1: '', v2: '', v3: '', v4: '' };
        const key = `v${(i % 4) + 1}`;
        prod.script[key] = smartFind(item, ['script', 'content', 'text']) || '';
        prod.images[key] = { 
          url: smartFind(item, ['outputImage', 'image', 'base64']) || '', 
          loading: false 
        };
        prod.videoPrompts[key] = { 
          text: smartFind(item, ['videoPrompt', 'prompt']) || '', 
          loading: false, 
          visible: !!smartFind(item, ['videoPrompt', 'prompt'])
        };

        if (i === 0) {
            setGender(smartFind(settings, ['gender']) || gender);
            setVoice(smartFind(settings, ['voice']) || voice);
            setImageStyle(smartFind(settings, ['imageStyle']) || imageStyle);
            setCommonNote(smartFind(settings, ['commonNote', 'note']) || commonNote);
        }

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { 
          detail: { percent, complete: i === total - 1 } 
        }));
        await new Promise(r => setTimeout(r, 30));
      }

      setProducts(newProducts);
      if (importedFaceBase64) setFacePreview(importedFaceBase64);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [products, gender, voice, imageStyle, commonNote, faceFile, facePreview]);

  const updateProduct = (id: number, updates: Partial<Shopee8sProduct>) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  const updateProductImage = (productId: number, imageKey: string, imgUpdates: Partial<GeneratedImage>) => {
    setProducts(prev => prev.map(p => {
      if (p.id !== productId) return p;
      const newImages = { ...p.images };
      newImages[imageKey] = { ...(newImages[imageKey] || { url: '', loading: false }), ...imgUpdates };
      return { ...p, images: newImages };
    }));
  };

  const updateProductVideoPrompt = (productId: number, promptKey: string, promptUpdates: Partial<VideoPromptState>) => {
    setProducts(prev => prev.map(p => {
      if (p.id !== productId) return p;
      const newPrompts = { ...p.videoPrompts };
      newPrompts[promptKey] = { ...(newPrompts[promptKey] || { text: '', loading: false, visible: false }), ...promptUpdates };
      return { ...p, videoPrompts: newPrompts };
    }));
  };

  const handleFileChange = (id: number, file: File | null) => {
    if (!file) return;
    const url = URL.createObjectURL(file);
    updateProduct(id, { file, previewUrl: url });
  };

  const handleGenerateAll = async () => {
    const productsToGen = products.filter(p => (p.file || p.previewUrl?.startsWith('data:')) && p.name);
    if (productsToGen.length === 0) {
      alert("Vui lòng tải ảnh và nhập tên cho ít nhất một sản phẩm.");
      return;
    }

    setIsGlobalLoading(true);
    try {
      const results = await Promise.all(productsToGen.map(async (product) => {
          const script = await service.generateShopee8sScript(product.name, product.usp, voice);
          const initialImages: any = {};
          const initialPrompts: any = {};
          ['v1', 'v2', 'v3', 'v4'].forEach(k => {
            initialImages[k] = { url: '', loading: false, customPrompt: '' };
            initialPrompts[k] = { text: '', loading: false, visible: false };
          });
          return { id: product.id, script, initialImages, initialPrompts };
      }));

      setProducts(prev => prev.map(p => {
        const res = results.find(r => r.id === p.id);
        return res ? { ...p, script: res.script, images: res.initialImages, videoPrompts: res.initialPrompts } : p;
      }));
    } catch (error) {
      alert("Lỗi khi tạo kịch bản.");
    } finally {
      setIsGlobalLoading(false);
    }
  };

  const handleGenImageForKey = async (productId: number, key: string) => {
    const product = products.find(p => p.id === productId);
    if (!product || !product.script) return;

    updateProductImage(productId, key, { loading: true, error: undefined });
    try {
      const imagePart = await getPartFromInput(product.file, product.previewUrl);
      if (!imagePart) throw new Error("No image");
      const facePart = await getPartFromInput(faceFile, facePreview);

      const charDesc = [
        product.action ? `Action: ${product.action}` : "",
        product.background ? `Background: ${product.background}` : "",
        commonNote, 
        product.images[key]?.customPrompt || ""
      ].filter(Boolean).join(". ");

      const imgUrl = await service.generateShopee8sImage(
        [imagePart], 
        product.name, 
        (product.script as any)[key], 
        charDesc,
        facePart,
        key === 'v2' || key === 'v4',
        imageStyle
      );
      updateProductImage(productId, key, { url: imgUrl, loading: false });
    } catch (error) {
      updateProductImage(productId, key, { loading: false, error: 'Lỗi' });
    }
  };

  const handleGenVideoPrompt = async (productId: number, key: string) => {
    const product = products.find(p => p.id === productId);
    if (!product || !product.script) return;

    updateProductVideoPrompt(productId, key, { text: '', loading: true, visible: true });
    try {
      const pPart = await getPartFromInput(product.file, product.previewUrl);
      const isNoProduct = (product.images[key]?.customPrompt || "").toLowerCase().includes("không có sản phẩm");
      const prompt = await service.generateShopee8sVeoPrompt(
        product.name,
        (product.script as any)[key],
        gender,
        voice,
        pPart?.data,
        product.images[key]?.url,
        isNoProduct,
        imageStyle
      );
      updateProductVideoPrompt(productId, key, { text: prompt, loading: false, visible: true });
    } catch (error) {
      updateProductVideoPrompt(productId, key, { text: 'Lỗi', loading: false });
    }
  };

  const handleBulkPrompt = async (pid: number) => {
    for (const key of ['v1', 'v2', 'v3', 'v4']) await handleGenVideoPrompt(pid, key);
  };

  const handleBulkImage = async (pid: number) => {
    for (const key of ['v1', 'v2', 'v3', 'v4']) await handleGenImageForKey(pid, key);
  };

  const handleDownloadAllZip = async () => {
    if (typeof JSZip === 'undefined') return alert("Loading ZIP lib...");
    const zip = new JSZip();
    let count = 0;
    products.forEach(p => {
      ['v1', 'v2', 'v3', 'v4'].forEach(k => {
        if (p.images[k]?.url) zip.file(`p${p.id}_${k}.png`, p.images[k].url.split(',')[1], { base64: true }), count++;
      });
    });
    if (count === 0) return alert("No images.");
    const blob = await zip.generateAsync({ type: "blob" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = "shopee8s_images.zip";
    link.click();
  };

  const hasAnyMedia = products.some(p => Object.values(p.images).some((img: any) => img.url));

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-[1.5rem] border border-slate-200 p-8 shadow-sm space-y-8">
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
          {products.map((p) => (
            <div 
              key={p.id}
              onClick={() => setActiveProductId(p.id)}
              className={`flex flex-col rounded-[1rem] border-2 p-3 transition-all cursor-pointer ${activeProductId === p.id ? 'border-[#ff5722] bg-white' : 'border-[#f1f5f9]'}`}
            >
              <div className="flex items-center gap-2 mb-3">
                <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${activeProductId === p.id ? 'border-[#ff5722] bg-[#ff5722]' : 'border-slate-300'}`}>
                  {activeProductId === p.id && <div className="w-1.5 h-1.5 bg-white rounded-full" />}
                </div>
                <span className="text-[11px] font-bold">SP {p.id}</span>
              </div>
              <div onClick={(e) => { e.stopPropagation(); fileInputRefs.current[p.id]?.click(); }} className="aspect-[4/5] bg-[#f8fafc] rounded-lg border border-dashed border-slate-200 mb-3 flex items-center justify-center overflow-hidden">
                {p.previewUrl ? <img src={p.previewUrl} className="w-full h-full object-cover" /> : <span className="text-[10px] font-bold opacity-40">TẢI ẢNH</span>}
                <input type="file" ref={el => { fileInputRefs.current[p.id] = el; }} onChange={(e) => handleFileChange(p.id, e.target.files?.[0] || null)} className="hidden" accept="image/*" />
              </div>
              <div className="space-y-2">
                <input value={p.name} onClick={e => e.stopPropagation()} onChange={e => updateProduct(p.id, { name: e.target.value })} placeholder="Tên SP..." className="w-full text-[11px] p-2 border border-slate-200 rounded outline-none" />
                <input value={p.usp} onClick={e => e.stopPropagation()} onChange={e => updateProduct(p.id, { usp: e.target.value })} placeholder="USP..." className="w-full text-[11px] p-2 border border-slate-200 rounded outline-none" />
