import { GoogleGenAI, Type } from "@google/genai";
import { ScriptParts } from "../types";
import { getAiClient } from "./keyService";

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const generateShopee8sScript = async (productName: string, usp: string, voice: string): Promise<ScriptParts> => {
  const ai = getAiClient();

  let dialectInstruction = voice === 'Miền Bắc (Hà Nội)'
    ? `VĂN PHONG MIỀN BẮC (HÀ NỘI): nhé, ạ, thế, đấy, chứ.` 
    : `VĂN PHONG MIỀN NAM (SÀI GÒN): nha, nè, nghen, thiệt, hông.`;

  const prompt = `Bạn là chuyên gia content Shopee. Sản phẩm: "${productName}". USP: "${usp}". Giọng: ${voice}. ${dialectInstruction}
  Tạo 2 video (v1,v2) và (v3,v4). Mỗi phần từ 160-180 ký tự. Trả về JSON v1,v2,v3,v4.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: [{ text: prompt }] },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: { v1: { type: Type.STRING }, v2: { type: Type.STRING }, v3: { type: Type.STRING }, v4: { type: Type.STRING } },
        required: ["v1", "v2", "v3", "v4"]
      }
    }
  });
  return JSON.parse(response.text || '{}');
};

export const generateShopee8sImage = async (
  imageParts: any[], 
  productName: string, 
  scriptPart: string, 
  charDesc: string,
  facePart: any | null,
  isFollowUp: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const baseStyle = is3D 
    ? "High-quality 3D Animation Pixar style, vibrant colors, expressive design."
    : "Photorealistic high-end commercial RAW PHOTO, 8k, cinematic lighting.";

  const scaleConsistencyRule = `
    !!! CRITICAL SCALE RULE (MANDATORY): PRODUCT-TO-CHARACTER RATIO !!!
    - The product "${productName}" MUST HAVE A FIXED PHYSICAL SIZE relative to the human model.
    - If the product is shown in reference as handheld, it MUST remain that size relative to the character body.
    - DO NOT change proportions. The scale of [Product] vs [Character] must be 100% consistent with the reference photo.
  `;

  const visualRules = `
    CRITICAL VISUAL RULES:
    1. ABSOLUTELY NO TEXT.
    2. CLEAN background.
    3. No UI elements.
    4. ${is3D ? "3D CGI look." : "Real photo look."}
    5. STRICT PRODUCT FIDELITY: Match input images 1:1. ${scaleConsistencyRule}
  `;

  const identityRule = facePart 
    ? `IDENTITY: Use face features from FACE_REFERENCE.`
    : `IDENTITY: Adult Vietnamese.`;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    CHARACTER: ${charDesc}. ${identityRule}
    ${visualRules}
    ${isFollowUp ? "Maintain character and background consistency from the previous shot." : ""}
    SCENE: "${scriptPart}".
  `;

  const contents: any[] = [{ text: prompt }];
  if (facePart) contents.push({ inlineData: facePart });
  if (imageParts.length > 0) contents.push({ inlineData: imageParts[0] });

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-image",
    contents: { parts: contents },
    config: { imageConfig: { aspectRatio: "9:16" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
};

export const generateShopee8sVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const scaleRule = `- CRITICAL: The product "${productName}" must maintain a constant size ratio relative to the character.`;

  const productInteractionRule = isNoProductRequested
    ? `- ABSOLUTELY NO product "${productName}".`
    : `- Character holding product "${productName}". ${scaleRule} - Match reference 1:1.`;

  const instructionPrompt = `
  Viết video prompt VEO-3 dài 8 giây. Style: ${is3D ? "3D Animation" : "Photorealistic"}.
  CẤU TRÚC:
  - NHÂN VẬT: Người Việt Nam. ${is3D ? "Pixar style." : "Real life."}
  - HÀNH ĐỘNG: ${productInteractionRule}. Character speaks in ${voice} voice: "${scriptText}"
  - BỐI CẢNH & ÁNH SÁNG: Phù hợp kịch bản.
  - KỸ THUẬT: 9:16, 4K, 60fps.
  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  if (generatedImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: contents }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) { return ""; }
};

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/shopee8sService';
import { Shopee8sProduct, ScriptParts, VideoPromptState, GeneratedImage } from '../types';
import ScriptSection from '../components/ScriptSection';
import ImageCard from '../components/ImageCard';

declare var JSZip: any;

const Shopee8sModule: React.FC = () => {
  const storageKey = "shopee8s_project_v10_media_sync";
  const [products, setProducts] = useState<Shopee8sProduct[]>(
    Array.from({ length: 5 }, (_, i) => ({
      id: i + 1,
      name: '',
      usp: '',
      background: '',
      action: '',
      file: null,
      previewUrl: null,
      script: null,
      images: {},
      videoPrompts: {},
      isLoading: false
    }))
  );

  const [faceFile, setFaceFile] = useState<File | null>(null);
  const [facePreview, setFacePreview] = useState<string | null>(null);
  const [gender, setGender] = useState<string>('Nữ');
  const [voice, setVoice] = useState<string>('Miền Bắc (Hà Nội)');
  const [imageStyle, setImageStyle] = useState<'Realistic' | '3D'>('Realistic');
  const [commonNote, setCommonNote] = useState('');
  const [isGlobalLoading, setIsGlobalLoading] = useState(false);
  // Add missing state for activeProductId and setActiveProductId
  const [activeProductId, setActiveProductId] = useState<number>(1);

  const fileInputRefs = useRef<(HTMLInputElement | null)[]>([]);
  const faceInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.products) {
          setProducts(prev => prev.map(p => {
            const savedP = parsed.products.find((sp: any) => sp.id === p.id);
            return savedP ? { 
              ...p, 
              ...savedP, 
              file: null, 
              // Note: We don't restore Base64 to LocalStorage to avoid quota limits, 
              // Base64 is only used for JSON Import/Export.
              isLoading: false,
              images: savedP.images || {},
              videoPrompts: savedP.videoPrompts || {}
            } : p;
          }));
        }
        if (parsed.commonNote) setCommonNote(parsed.commonNote);
        if (parsed.gender) setGender(parsed.gender);
        if (parsed.voice) setVoice(parsed.voice);
        if (parsed.imageStyle) setImageStyle(parsed.imageStyle);
      }
    } catch (e) { console.error("Restore fail", e); }
  }, []);

  useEffect(() => {
    try {
      const persistentProducts = products.map(({ file, previewUrl, isLoading, images, videoPrompts, ...rest }) => {
        const safeImages = Object.keys(images || {}).reduce((acc: any, key) => {
           acc[key] = { ...images[key], url: '' }; 
           return acc;
        }, {});
        return { 
          ...rest, 
          images: safeImages, 
          videoPrompts: videoPrompts || {} 
        };
      });
      localStorage.setItem(storageKey, JSON.stringify({ products: persistentProducts, commonNote, gender, voice, imageStyle }));
    } catch (e) { }
  }, [products, commonNote, gender, voice, imageStyle]);

  // Helper to get Base64 from File or existing Base64 URL
  const getMediaBase64 = async (file: File | null, existingUrl: string | null) => {
    if (file) {
      const part = await service.fileToGenerativePart(file);
      return `data:${part.mimeType};base64,${part.data}`;
    }
    if (existingUrl?.startsWith('data:')) return existingUrl;
    return null;
  };

  // Helper to convert File/Base64 to AI Part
  const getPartFromInput = async (file: File | null, url: string | null) => {
    if (file) return await service.fileToGenerativePart(file);
    if (url?.startsWith('data:')) {
      return { mimeType: 'image/png', data: url.split(',')[1] };
    }
    return null;
  };

  // Handle Global Import / Export with Media
  useEffect(() => {
    const handleExport = async () => {
      const faceBase64 = await getMediaBase64(faceFile, facePreview);

      const exportDataPromises = products.map(async (p) => {
        if (!p.script) return null;

        const productBase64 = await getMediaBase64(p.file, p.previewUrl);

        return ['v1', 'v2', 'v3', 'v4'].map(key => ({
          inputs: {
            productName: p.name,
            usp: p.usp,
            background: p.background,
            action: p.action,
            // Package media into JSON
            inputMedia: {
              productImage: productBase64,
              faceImage: faceBase64
            },
            settings: {
              gender,
              voice,
              imageStyle,
              commonNote
            }
          },
          script: (p.script as any)[key],
          outputImage: p.images[key]?.url || '',
          videoPrompt: p.videoPrompts[key]?.text || ''
        }));
      });

      const results = (await Promise.all(exportDataPromises)).filter(r => r !== null).flat();
      const finalExport = results.map((item, idx) => ({ ...item, stt: idx + 1 }));

      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data: finalExport, moduleName: 'Shopee_Video_Full_Media' } 
      }));
    };

    const smartFind = (obj: any, keys: string[]) => {
      if (!obj) return undefined;
      const lowerKeys = keys.map(k => k.toLowerCase());
      const foundKey = Object.keys(obj).find(k => lowerKeys.includes(k.toLowerCase()));
      return foundKey ? obj[foundKey] : undefined;
    };

    const handleImport = async (e: any) => {
      const importedData = e.detail;
      if (!Array.isArray(importedData) || importedData.length === 0) return;

      const newProducts = Array.from({ length: 5 }, (_, i) => ({
        id: i + 1,
        name: '',
        usp: '',
        background: '',
        action: '',
        file: null,
        previewUrl: null,
        script: null,
        images: {},
        videoPrompts: {},
        isLoading: false
      }));

      const total = importedData.length;
      let importedFaceBase64 = "";

      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        const inputs = smartFind(item, ['inputs', 'data']) || {};
        const media = smartFind(inputs, ['inputMedia', 'media']) || {};
        const settings = smartFind(inputs, ['settings', 'config']) || {};

        const prodIndex = Math.floor(i / 4);
        if (prodIndex >= newProducts.length) break;

        const prod = newProducts[prodIndex];
        prod.name = smartFind(inputs, ['productName', 'name']) || prod.name;
        prod.usp = smartFind(inputs, ['usp', 'keyword']) || prod.usp;
        prod.background = smartFind(inputs, ['background']) || prod.background;
        prod.action = smartFind(inputs, ['action']) || prod.action;

        // Restore product image from Base64
        const pImg = smartFind(media, ['productImage', 'product_img']);
        if (pImg && !prod.previewUrl) prod.previewUrl = pImg;

        // Restore face image from Base64 (shared)
        const fImg = smartFind(media, ['faceImage', 'face']);
        if (fImg) importedFaceBase64 = fImg;

        if (!prod.script) prod.script = { v1: '', v2: '', v3: '', v4: '' };
        const key = `v${(i % 4) + 1}`;
        prod.script[key] = smartFind(item, ['script', 'content', 'text']) || '';
        prod.images[key] = { 
          url: smartFind(item, ['outputImage', 'image', 'base64']) || '', 
          loading: false 
        };
        prod.videoPrompts[key] = { 
          text: smartFind(item, ['videoPrompt', 'prompt']) || '', 
          loading: false, 
          visible: !!smartFind(item, ['videoPrompt', 'prompt'])
        };

        if (i === 0) {
            setGender(smartFind(settings, ['gender']) || gender);
            setVoice(smartFind(settings, ['voice']) || voice);
            setImageStyle(smartFind(settings, ['imageStyle']) || imageStyle);
            setCommonNote(smartFind(settings, ['commonNote', 'note']) || commonNote);
        }

        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { 
          detail: { percent, complete: i === total - 1 } 
        }));
        await new Promise(r => setTimeout(r, 30));
      }

      setProducts(newProducts);
      if (importedFaceBase64) setFacePreview(importedFaceBase64);
    };

    window.addEventListener('REQUEST_EXPORT_DATA', handleExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleImport);
    };
  }, [products, gender, voice, imageStyle, commonNote, faceFile, facePreview]);

  const updateProduct = (id: number, updates: Partial<Shopee8sProduct>) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  const updateProductImage = (productId: number, imageKey: string, imgUpdates: Partial<GeneratedImage>) => {
    setProducts(prev => prev.map(p => {
      if (p.id !== productId) return p;
      const newImages = { ...p.images };
      newImages[imageKey] = { ...(newImages[imageKey] || { url: '', loading: false }), ...imgUpdates };
      return { ...p, images: newImages };
    }));
  };

  const updateProductVideoPrompt = (productId: number, promptKey: string, promptUpdates: Partial<VideoPromptState>) => {
    setProducts(prev => prev.map(p => {
      if (p.id !== productId) return p;
      const newPrompts = { ...p.videoPrompts };
      newPrompts[promptKey] = { ...(newPrompts[promptKey] || { text: '', loading: false, visible: false }), ...promptUpdates };
      return { ...p, videoPrompts: newPrompts };
    }));
  };

  const handleFileChange = (id: number, file: File | null) => {
    if (!file) return;
    const url = URL.createObjectURL(file);
    updateProduct(id, { file, previewUrl: url });
  };

  const handleGenerateAll = async () => {
    const productsToGen = products.filter(p => (p.file || p.previewUrl?.startsWith('data:')) && p.name);
    if (productsToGen.length === 0) {
      alert("Vui lòng tải ảnh và nhập tên cho ít nhất một sản phẩm.");
      return;
    }

    setIsGlobalLoading(true);
    try {
      const results = await Promise.all(productsToGen.map(async (product) => {
          const script = await service.generateShopee8sScript(product.name, product.usp, voice);
          const initialImages: any = {};
          const initialPrompts: any = {};
          ['v1', 'v2', 'v3', 'v4'].forEach(k => {
            initialImages[k] = { url: '', loading: false, customPrompt: '' };
            initialPrompts[k] = { text: '', loading: false, visible: false };
          });
          return { id: product.id, script, initialImages, initialPrompts };
      }));

      setProducts(prev => prev.map(p => {
        const res = results.find(r => r.id === p.id);
        return res ? { ...p, script: res.script, images: res.initialImages, videoPrompts: res.initialPrompts } : p;
      }));
    } catch (error) {
      alert("Lỗi khi tạo kịch bản.");
    } finally {
      setIsGlobalLoading(false);
    }
  };

  const handleGenImageForKey = async (productId: number, key: string) => {
    const product = products.find(p => p.id === productId);
    if (!product || !product.script) return;

    updateProductImage(productId, key, { loading: true, error: undefined });
    try {
      const imagePart = await getPartFromInput(product.file, product.previewUrl);
      if (!imagePart) throw new Error("No image");
      const facePart = await getPartFromInput(faceFile, facePreview);

      const charDesc = [
        product.action ? `Action: ${product.action}` : "",
        product.background ? `Background: ${product.background}` : "",
        commonNote, 
        product.images[key]?.customPrompt || ""
      ].filter(Boolean).join(". ");

      const imgUrl = await service.generateShopee8sImage(
        [imagePart], 
        product.name, 
        (product.script as any)[key], 
        charDesc,
        facePart,
        key === 'v2' || key === 'v4',
        imageStyle
      );
      updateProductImage(productId, key, { url: imgUrl, loading: false });
    } catch (error) {
      updateProductImage(productId, key, { loading: false, error: 'Lỗi' });
    }
  };

  const handleGenVideoPrompt = async (productId: number, key: string) => {
    const product = products.find(p => p.id === productId);
    if (!product || !product.script) return;

    updateProductVideoPrompt(productId, key, { text: '', loading: true, visible: true });
    try {
      const pPart = await getPartFromInput(product.file, product.previewUrl);
      const isNoProduct = (product.images[key]?.customPrompt || "").toLowerCase().includes("không có sản phẩm");
      const prompt = await service.generateShopee8sVeoPrompt(
        product.name,
        (product.script as any)[key],
        gender,
        voice,
        pPart?.data,
        product.images[key]?.url,
        isNoProduct,
        imageStyle
      );
      updateProductVideoPrompt(productId, key, { text: prompt, loading: false, visible: true });
    } catch (error) {
      updateProductVideoPrompt(productId, key, { text: 'Lỗi', loading: false });
    }
  };

  const handleBulkPrompt = async (pid: number) => {
    for (const key of ['v1', 'v2', 'v3', 'v4']) await handleGenVideoPrompt(pid, key);
  };

  const handleBulkImage = async (pid: number) => {
    for (const key of ['v1', 'v2', 'v3', 'v4']) await handleGenImageForKey(pid, key);
  };

  const handleDownloadAllZip = async () => {
    if (typeof JSZip === 'undefined') return alert("Loading ZIP lib...");
    const zip = new JSZip();
    let count = 0;
    products.forEach(p => {
      ['v1', 'v2', 'v3', 'v4'].forEach(k => {
        if (p.images[k]?.url) zip.file(`p${p.id}_${k}.png`, p.images[k].url.split(',')[1], { base64: true }), count++;
      });
    });
    if (count === 0) return alert("No images.");
    const blob = await zip.generateAsync({ type: "blob" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = "shopee8s_images.zip";
    link.click();
  };

  const hasAnyMedia = products.some(p => Object.values(p.images).some((img: any) => img.url));

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-[1.5rem] border border-slate-200 p-8 shadow-sm space-y-8">
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
          {products.map((p) => (
            <div 
              key={p.id}
              onClick={() => setActiveProductId(p.id)}
              className={`flex flex-col rounded-[1rem] border-2 p-3 transition-all cursor-pointer ${activeProductId === p.id ? 'border-[#ff5722] bg-white' : 'border-[#f1f5f9]'}`}
            >
              <div className="flex items-center gap-2 mb-3">
                <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${activeProductId === p.id ? 'border-[#ff5722] bg-[#ff5722]' : 'border-slate-300'}`}>
                  {activeProductId === p.id && <div className="w-1.5 h-1.5 bg-white rounded-full" />}
                </div>
                <span className="text-[11px] font-bold">SP {p.id}</span>
              </div>
              <div onClick={(e) => { e.stopPropagation(); fileInputRefs.current[p.id]?.click(); }} className="aspect-[4/5] bg-[#f8fafc] rounded-lg border border-dashed border-slate-200 mb-3 flex items-center justify-center overflow-hidden">
                {p.previewUrl ? <img src={p.previewUrl} className="w-full h-full object-cover" /> : <span className="text-[10px] font-bold opacity-40">TẢI ẢNH</span>}
                <input type="file" ref={el => { fileInputRefs.current[p.id] = el; }} onChange={(e) => handleFileChange(p.id, e.target.files?.[0] || null)} className="hidden" accept="image/*" />
              </div>
              <div className="space-y-2">
                <input value={p.name} onClick={e => e.stopPropagation()} onChange={e => updateProduct(p.id, { name: e.target.value })} placeholder="Tên SP..." className="w-full text-[11px] p-2 border border-slate-200 rounded outline-none" />
                <input value={p.usp} onClick={e => e.stopPropagation()} onChange={e => updateProduct(p.id, { usp: e.target.value })} placeholder="USP..." className="w-full text-[11px] p-2 border border-slate-200 rounded outline-none" />
                <input value={p.background} onClick={e => e.stopPropagation()} onChange={e => updateProduct(p.id, { background: e.target.value })} placeholder="Bối cảnh..." className="w-full text-[11px] p-2 border border-slate-200 rounded outline-none" />
                <input value={p.action} onClick={e => e.stopPropagation()} onChange={e => updateProduct(p.id, { action: e.target.value })} placeholder="Hành động..." className="w-full text-[11px] p-2 border border-slate-200 rounded outline-none" />
              </div>
            </div>
          ))}
        </div>

        <div className="bg-white rounded-2xl border border-slate-200 p-8 grid grid-cols-1 md:grid-cols-2 gap-8">
             <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-[11px] font-black text-slate-400 uppercase">Giới tính</label>
                    <select value={gender} onChange={e => setGender(e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold">
                        <option value="Nữ">Nữ</option><option value="Nam">Nam</option>
                    </select>
                  </div>
                  <div>
                    <label className="text-[11px] font-black text-slate-400 uppercase">Phong cách</label>
                    <div className="flex bg-slate-50 p-1 rounded-xl border border-slate-200">
                      <button onClick={() => setImageStyle('Realistic')} className={`flex-1 py-1.5 text-[10px] font-black rounded-lg ${imageStyle === 'Realistic' ? 'bg-orange-600 text-white' : 'text-slate-400'}`}>REAL</button>
                      <button onClick={() => setImageStyle('3D')} className={`flex-1 py-1.5 text-[10px] font-black rounded-lg ${imageStyle === '3D' ? 'bg-orange-600 text-white' : 'text-slate-400'}`}>3D</button>
                    </div>
                  </div>
                </div>
                <div>
                  <label className="text-[11px] font-black text-slate-400 uppercase">Giọng điệu</label>
                  <select value={voice} onChange={e => setVoice(e.target.value)} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold">
                      <option value="Miền Bắc (Hà Nội)">Miền Bắc (Hà Nội)</option><option value="Miền Nam (Sài Gòn)">Miền Nam (Sài Gòn)</option>
                  </select>
                </div>
             </div>
             <div>
                <label className="text-[11px] font-black text-slate-400 uppercase">Ảnh mặt mẫu (Base64 ready)</label>
                <div className="flex gap-4">
                  <div onClick={() => faceInputRef.current?.click()} className="w-24 h-24 border-2 border-dashed border-slate-200 rounded-xl flex items-center justify-center cursor-pointer bg-slate-50 overflow-hidden">
                    {facePreview ? <img src={facePreview} className="w-full h-full object-cover" /> : <svg className="w-8 h-8 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 4v16m8-8H4" /></svg>}
                    <input type="file" faceInputRef={faceInputRef} onChange={(e) => { const f = e.target.files?.[0]; if (f) { setFaceFile(f); setFacePreview(URL.createObjectURL(f)); } }} className="hidden" accept="image/*" />
                  </div>
                  <textarea value={commonNote} onChange={(e) => setCommonNote(e.target.value)} placeholder="Ghi chú nhân vật..." className="flex-1 h-24 p-3 bg-slate-50 border border-slate-200 rounded-xl text-xs outline-none" />
                </div>
             </div>
        </div>

        <button onClick={handleGenerateAll} disabled={isGlobalLoading} className="w-full py-5 bg-slate-900 text-white font-black rounded-xl text-lg hover:bg-orange-600 transition-all disabled:opacity-50">
          {isGlobalLoading ? "ĐANG TẠO..." : "TẠO KỊCH BẢN BỘ"}
        </button>
      </div>

      {products.filter(p => p.script).length > 0 && (
        <div className="mt-12 space-y-16 pb-12">
          {products.filter(p => p.script).map((p) => (
            <div key={p.id} className="animate-fadeIn bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm">
              <h2 className="text-2xl font-black text-slate-800 mb-8 px-2 flex items-center gap-3">
                <span className="bg-orange-600 text-white w-8 h-8 rounded-full flex items-center justify-center text-sm">{p.id}</span>
                {p.name.toUpperCase()}
              </h2>
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="space-y-6">
                   <h3 className="text-sm font-black text-orange-600 uppercase border-b pb-2 tracking-widest">VIDEO 1 (16S)</h3>
                   <div className="grid grid-cols-2 gap-4">
                      {['v1', 'v2'].map(k => (
                         <div key={k} className="space-y-3">
                           <ScriptSection title={k === 'v1' ? "Intro" : "Detail"} content={(p.script as any)[k]} color="border-orange-500" onChange={val => updateProduct(p.id, { script: { ...p.script, [k]: val } as any })} />
                           <ImageCard label={k} imageData={p.images[k] || { url: '', loading: false }} videoPrompt={(p.videoPrompts as any)?.[k] || { text: '', loading: false, visible: false }} onGeneratePrompt={() => handleGenVideoPrompt(p.id, k)} onRegenerate={() => handleGenImageForKey(p.id, k)} onTranslate={() => {}} customPrompt={p.images[k]?.customPrompt || ""} onCustomPromptChange={val => updateProductImage(p.id, k, { customPrompt: val })} />
                         </div>
                      ))}
                   </div>
                </div>
                <div className="space-y-6">
                   <h3 className="text-sm font-black text-blue-600 uppercase border-b pb-2 tracking-widest">VIDEO 2 (16S)</h3>
                   <div className="grid grid-cols-2 gap-4">
                      {['v3', 'v4'].map(k => (
                         <div key={k} className="space-y-3">
                           <ScriptSection title={k === 'v3' ? "Hook" : "CTA"} content={(p.script as any)[k]} color="border-blue-500" onChange={val => updateProduct(p.id, { script: { ...p.script, [k]: val } as any })} />
                           <ImageCard label={k} imageData={p.images[k] || { url: '', loading: false }} videoPrompt={(p.videoPrompts as any)?.[k] || { text: '', loading: false, visible: false }} onGeneratePrompt={() => handleGenVideoPrompt(p.id, k)} onRegenerate={() => handleGenImageForKey(p.id, k)} onTranslate={() => {}} customPrompt={p.images[k]?.customPrompt || ""} onCustomPromptChange={val => updateProductImage(p.id, k, { customPrompt: val })} />
                         </div>
                      ))}
                   </div>
                </div>
              </div>
              <div className="flex justify-center mt-10 gap-4">
                <button onClick={() => handleBulkImage(p.id)} className="px-8 py-3 bg-orange-600 text-white font-black rounded-xl text-xs uppercase tracking-widest shadow-lg">Tạo All Ảnh</button>
                <button onClick={() => handleBulkPrompt(p.id)} className="px-8 py-3 bg-slate-900 text-white font-black rounded-xl text-xs uppercase tracking-widest shadow-lg">Tạo All Prompts</button>
              </div>
            </div>
          ))}
          {hasAnyMedia && (
            <div className="flex justify-center border-t pt-10">
              <button onClick={handleDownloadAllZip} className="px-12 py-5 bg-slate-900 text-white font-black rounded-2xl shadow-xl hover:bg-black uppercase tracking-widest">Tải Toàn Bộ Ảnh (ZIP)</button>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default Shopee8sModule;
